public class SpringBootDockerfileGenerator {

    public record AppConfig(
        String appName,
        String mainClass,
        String javaVersion,
        int serverPort,
        boolean enableHealthCheck
    ) {}

    public String generate(AppConfig config) {
        StringBuilder sb = new StringBuilder();

        // Stage 1: Build
        sb.append("# Build stage\n");
        sb.append("FROM maven:3.9-eclipse-temurin-").append(config.javaVersion()).append(" AS build\n");
        sb.append("WORKDIR /build\n");
        // Copy pom.xml first for dependency caching
        sb.append("COPY pom.xml .\n");
        sb.append("RUN mvn dependency:go-offline -q\n");
        sb.append("COPY src ./src\n");
        sb.append("RUN mvn package -DskipTests -q\n");
        sb.append("\n");

        // Stage 2: Runtime
        sb.append("# Runtime stage\n");
        sb.append("FROM eclipse-temurin:");
        // TODO: append java version and '-jre-alpine' for lean image
        sb.append("\n");
        sb.append("WORKDIR /app\n");
        sb.append("COPY --from=build /build/target/*.jar app.jar\n");

        // TODO: add EXPOSE instruction using config.serverPort()
        // TODO: if enableHealthCheck, add HEALTHCHECK instruction
        // TODO: add non-root USER instruction (uid 1001)
        // TODO: add ENTRYPOINT

        return sb.toString();
    }

    public static void main(String[] args) {
        SpringBootDockerfileGenerator gen = new SpringBootDockerfileGenerator();
        AppConfig config = new AppConfig("myapp", "com.example.Application", "17", 8080, true);
        System.out.print(gen.generate(config));
    }
}

