public class DockerComposeResolver {

    private final Map<String, List<String>> services = new LinkedHashMap<>();

    public void addService(String name, String... dependsOn) {
        services.put(name, new ArrayList<>(List.of(dependsOn)));
    }

    public List<String> startupOrder() {
        // Return services in topological order (dependencies first)
        // Throw IllegalStateException if circular dependency detected
        List<String> order = new ArrayList<>();
        Set<String> visited = new HashSet<>();
        Set<String> inProgress = new HashSet<>();

        for (String service : services.keySet()) {
            if (!visited.contains(service)) {
                dfs(service, visited, inProgress, order);
            }
        }
        return order;
    }

    private void dfs(String service, Set<String> visited, Set<String> inProgress, List<String> order) {
        // TODO: implement DFS with cycle detection
    }

    public List<String> findCircularDependencies() {
        // Return list of services involved in circular dependencies, or empty list
        try {
            startupOrder();
            return new ArrayList<>();
        } catch (IllegalStateException e) {
            // Re-detect which services form the cycle
            return detectCycles();
        }
    }

    private List<String> detectCycles() {
        List<String> cycleParticipants = new ArrayList<>();
        Set<String> visited = new HashSet<>();
        Set<String> inProgress = new HashSet<>();
        for (String s : services.keySet()) {
            if (!visited.contains(s)) {
                collectCycles(s, visited, inProgress, cycleParticipants);
            }
        }
        return cycleParticipants;
    }

    private void collectCycles(String s, Set<String> visited, Set<String> inProgress, List<String> result) {
        inProgress.add(s);
        for (String dep : services.getOrDefault(s, List.of())) {
            if (inProgress.contains(dep) && !result.contains(dep)) result.add(dep);
            else if (!visited.contains(dep)) collectCycles(dep, visited, inProgress, result);
        }
        inProgress.remove(s);
        visited.add(s);
    }

    public static void main(String[] args) {
        DockerComposeResolver resolver = new DockerComposeResolver();
        resolver.addService("app", "database", "redis");
        resolver.addService("database");
        resolver.addService("redis");
        resolver.addService("nginx", "app");

        System.out.println("Startup order: " + resolver.startupOrder());
        System.out.println("Cycles: " + resolver.findCircularDependencies());
    }
}

import java.util.*;

public class EnvVarInjector {

    public enum Source {
        DOCKERFILE_DEFAULT,  // lowest priority
        COMPOSE_ENV,
        RUNTIME_OVERRIDE     // highest priority
    }

    private final Map<Source, Map<String, String>> envSources = new EnumMap<>(Source.class);

    public void addEnv(Source source, Map<String, String> vars) {
        envSources.computeIfAbsent(source, k -> new HashMap<>()).putAll(vars);
    }

    public Map<String, String> resolve() {
        // Merge all sources in precedence order (lowest to highest)
        // Higher priority sources override lower ones
        Map<String, String> result = new LinkedHashMap<>();
        // Process in order: DOCKERFILE_DEFAULT -> COMPOSE_ENV -> RUNTIME_OVERRIDE
        for (Source source : new Source[]{Source.DOCKERFILE_DEFAULT, Source.COMPOSE_ENV, Source.RUNTIME_OVERRIDE}) {
            Map<String, String> vars = envSources.getOrDefault(source, Map.of());
            result.putAll(vars);
        }
        return result;
    }

    public String get(String key) {
        return resolve().get(key);
    }

    public boolean hasKey(String key) {
        return resolve().containsKey(key);
    }

    public static void main(String[] args) {
        EnvVarInjector injector = new EnvVarInjector();
        injector.addEnv(Source.DOCKERFILE_DEFAULT, Map.of(
            "DB_HOST", "localhost", "LOG_LEVEL", "DEBUG", "PORT", "8080"
        ));
        injector.addEnv(Source.COMPOSE_ENV, Map.of(
            "DB_HOST", "postgres", "DB_USER", "appuser"
        ));
        injector.addEnv(Source.RUNTIME_OVERRIDE, Map.of(
            "LOG_LEVEL", "WARN"
        ));

        Map<String, String> resolved = injector.resolve();
        System.out.println("DB_HOST: " + resolved.get("DB_HOST"));
        System.out.println("LOG_LEVEL: " + resolved.get("LOG_LEVEL"));
        System.out.println("Total vars: " + resolved.size());
    }
}
